import{_ as e,o as n,c as i,a as r}from"./app.3c51edca.js";var a="/images/diy/t2lt/t2lt-fertig-gebaut.jpeg",t="/images/diy/t2lt/t2lt-bauteile.jpeg",s="/images/diy/t2lt/t2lt-werkzeuge.jpeg",d="/images/diy/t2lt/t2lt-zeichnung-antennenaufbau.jpg",l="/images/diy/t2lt/t2lt-bnc-stecker.jpeg",c="/images/diy/t2lt/t2lt-spule-gewickelt.jpeg",h="/images/diy/t2lt/t2lt-kabelende-abisoliert.jpeg",u="/images/diy/t2lt/t2lt-schrumpfschlauch-pre.jpeg",m="/images/diy/t2lt/t2lt-schrumpfschlauch-done.jpeg",o="/images/diy/t2lt/t2lt-schnur-schleife.jpeg";const b={},p=r('<h1 id="t2lt-antenne-fur-2m-und-70cm" tabindex="-1"><a class="header-anchor" href="#t2lt-antenne-fur-2m-und-70cm" aria-hidden="true">#</a> T2LT Antenne f\xFCr 2m und 70cm</h1><p>Eine portable 2m und 70cm T2LT Antenne f\xFCr kleines Geld - selbstgebaut. Sehr einfach zu bauen und damit perfekt f\xFCr Einsteiger.</p><p><img src="'+a+'" alt="Fertig gebaute Antenne"></p><h2 id="bauteile" tabindex="-1"><a class="header-anchor" href="#bauteile" aria-hidden="true">#</a> Bauteile</h2><p>Die Antenne besteht im Wesentlichen aus einem einfachem RG-174 Koaxialkabel mit einer gewickelten Spule.</p><p><img src="'+t+'" alt="Bauteile"></p><ul><li>6 m an RG-174 Koax-Kabel</li><li>ca. 5 cm PVC oder HDPE-Rohr mit einem Gesamtdurchmesser von 25 mm als Spulenk\xF6rper</li><li>ca. 5 cm an gro\xDFem Schrumpfschlau, der das Rohr + die Wicklungen \xFCberdecken kann</li><li>1 m d\xFCnne Schnur (hierbei empfehlen wir eine gut sichtbare Farbe zu w\xE4hlen, Stichwort &quot;high visibility&quot;)</li><li>ca. 90 cm an d\xFCnnen Schrumpfschlau der \xFCber das Kabel + Schnur passt</li><li>BNC-Stecker passend zum Kabeldurchmesser zum Ancrimpen (oder anderer gew\xFCnschter Stecker)</li><li>Klett-Kabelbinder</li></ul><div class="custom-container tip"><p class="custom-container-title">Tipp</p><p>Wie bei allen Drau\xDFenfunker-Antennen k\xF6nnt ihr auf dem Discord-Server mal nachfragen, ob euch jemand ein Bastel-Kit f\xFCr diese Antenne zusammenstellen und zuschicken kann. Zu Material + Versandkosten Preisen.</p></div><h2 id="werkzeug" tabindex="-1"><a class="header-anchor" href="#werkzeug" aria-hidden="true">#</a> Werkzeug</h2><p><img src="'+s+'" alt="Werkzeuge"></p><ul><li>Abisolierzange</li><li>BNC-Crimpzange</li><li>ggf. einen L\xF6tkolben, je nach BNC-Stecker</li><li>Bohrer, 3 mm</li><li>Seitenschneider oder Kabelschere</li><li>Ma\xDFband oder Zollstock</li><li>Hei\xDFluftgebl\xE4se oder F\xF6hn</li><li>Stift oder Tape f\xFCr Markierungen</li><li>Sekundenkleber</li></ul><h2 id="zusammenbau" tabindex="-1"><a class="header-anchor" href="#zusammenbau" aria-hidden="true">#</a> Zusammenbau</h2><p>Das Ziel besteht darin, die folgende Konstruktion herzustellen:</p><p><img src="'+d+'" alt="Zeichnung Antennenaufbau"></p><h3 id="bnc-stecker-anbringen" tabindex="-1"><a class="header-anchor" href="#bnc-stecker-anbringen" aria-hidden="true">#</a> BNC-Stecker anbringen</h3><p>Wir beginnen damit, den BNC-Stecker an einer Seite des Kabels anzubringen. Daf\xFCr m\xFCssen wir das Kabel in verschiedenen Tiefen abisolieren.</p><p>In diesem Beispiel nutzen wir einen BNC-Stecker mit einem kleinen L\xF6tfenster, in dem das Kupfer angel\xF6tet werden muss. Es gibt aber auch andere Stecker, die nur gecrimpt werden m\xFCssen, beispielsweise mit einem goldenen Pin. F\xFCr unseren Stecker m\xFCssen wir am Ende lediglich ein kleines St\xFCck Kupfer vollst\xE4ndig abisolieren, damit es angel\xF6tet werden kann. Der Kupferteil sollte dabei nur so lang sein, dass es im Kontakt liegt. Die wei\xDFe bzw. transparente Innenisolierung sollte so lang sein, dass sie durch das Rohr geht und im L\xF6tfenster minimal herausguckt. Dadurch wird sichergestellt, dass der Innenleiter des Kabels innerhalb des Rohrs keinen Kontakt zum Geh\xE4use bekommt. Das Schirmgeflecht sollte dann \xFCber den geriffelten Teil des Rohrs gef\xFChrt werden. Der Kabelmantel sollte direkt am \xE4u\xDFeren Ende des Rohrs abschlie\xDFen.</p><p>Nachdem das Kabel richtig abisoliert wurde, muss es durch das Rohr gef\xFChrt und dann angel\xF6tet werden. Nach erfolgtem Anl\xF6ten kann die Kapsel dar\xFCbergezogen und angecrimpt werden.</p><p><img src="'+l+'" alt="Foto BNC-Stecker Anbringung"></p><h3 id="spule-vorbereiten-und-wickeln" tabindex="-1"><a class="header-anchor" href="#spule-vorbereiten-und-wickeln" aria-hidden="true">#</a> Spule vorbereiten und wickeln</h3><p>Danach messen wir 5 m auf dem Kabel <strong>hinter</strong> dem BNC-Stecker ab und markieren die Stelle mit einem Stift oder Tape. Anschlie\xDFend bohren wir drei L\xF6cher in die Spule bzw. das Rohr. Zwei davon befinden sich jeweils mittig auf der Spule, links und rechts, mit einem Abstand von 27 mm zueinander.</p><div class="custom-container tip"><p class="custom-container-title">Tipp</p><p>Testweise solltet ihr das Kabel <strong>vor</strong> den Bohrungen auf dem Rohr aufwickeln und messen, wie breit die L\xF6cher f\xFCr die neun Wicklungen bei euch auseinander sein m\xFCssen. Je nachdem wie dick euer Koax-Kabel ist, braucht ihr mehr als die 27 mm Abstand.</p></div><p>Das dritte Loch kommt auf der rechten Seite etwas unter dem bereits gebohrten Loch. Es kann aber auch etwas weiter rechts davon gebohrt werden, falls ihr noch Platz habt, sodass ihr die Schnur besser anknoten k\xF6nnt.</p><p>Nach den gebohrten L\xF6chern kommen wir nun zur Wicklung der Spule. Zieht dazu das Kabel am Antennenende durch das erste Loch (linke Seite) von innen nach au\xDFen, bis ihr die markierte Stelle bei 5 m erreicht habt. Ihr solltet jetzt links vom Loch euer 5 m langes Kabel mit dem angecrimpten BNC-Stecker haben, w\xE4hrend der Rest oberhalb des Rohrs liegt. Wickelt das Kabel nun <strong>neun Mal</strong> eng um das Rohr und steckt das restliche Kabel anschlie\xDFend in das Loch des Rohrs, sodass es auf der Innenseite wieder herauskommt.</p><p>Bevor ihr alles strammzieht, m\xFCsst ihr die Schnur noch durch das dritte Loch f\xFChren und anknoten. Wenn die Wicklungen sch\xF6n stramm und eng sind, k\xF6nnt ihr optional noch etwas Sekundenkleber an den L\xF6chern und dem Knoten auftragen.</p><p><img src="'+c+'" alt="Foto gewickelte Spule"></p><h3 id="antennenleiter" tabindex="-1"><a class="header-anchor" href="#antennenleiter" aria-hidden="true">#</a> Antennenleiter</h3><p>Dann messen wir ca. 45 cm vom Kabel nach der Spule ab und markieren diese Stelle erneut mit einem Stift oder Tape. Ab dieser Markierung messen wir weitere 43,5 cm ab und markieren auch diese Stelle oder schneiden das \xFCbersch\xFCssige Kabel direkt nach dieser Stelle ab.</p><p>Anschlie\xDFend entfernen wir vom Ende des Kabels (vorausgesetzt, das \xFCbersch\xFCssige Kabel wurde bereits abgeschnitten) bis zur Markierung den Mantel und die Schirmung.</p><p><strong>Wichtig</strong>: der wei\xDFe bzw. durchsichtige Innenleiter bleibt dabei dran!</p><div class="custom-container tip"><p class="custom-container-title">Tipp</p><p>Um die Schirmung einfacher zu entfernen, schiebt ihr diese bis zur Markierung nach unten. Dadurch staut sich das Material und kann dann ganz unten an der Markierung abgeschnitten werden.</p></div><p>Dieser 43,5 cm lange, offene Teil des Kabels ist dann die eigentliche Antenne.</p><p><img src="'+h+'" alt="Foto Kabelende abisoliert"></p><h3 id="schrumpfschlauche" tabindex="-1"><a class="header-anchor" href="#schrumpfschlauche" aria-hidden="true">#</a> Schrumpfschl\xE4uche</h3><p>Zuerst den d\xFCnnen Schrumpfschlauch \xFCber die Schnur <strong>und</strong> das Ende mit dem abisolierten Kabel ziehen. Dies ist etwas fummelig und kann auch etwas dauern, vor allem mit der Schnur. Danach kann ganz einfach der gro\xDFe Schrumpfschlauch \xFCber den d\xFCnnen gezogen werden, bis er die gewickelte Spule bedeckt.</p><p><img src="'+u+'" alt="Foto Schrumpfschlauch vor dem Schrumpfen"></p><p>Nun k\xF6nnen wir beide Schrumpfschl\xE4uche nacheinander schrumpfen.</p><p><img src="'+m+'" alt="Foto Schrumpfschlauch nach dem Schrumpfen"></p><h3 id="abschluss" tabindex="-1"><a class="header-anchor" href="#abschluss" aria-hidden="true">#</a> Abschluss</h3><p>Damit die Antenne einsatzbereit ist, m\xFCssen wir mit der \xFCbersch\xFCssigen Schnur noch eine Schleife binden. Daf\xFCr wurde bei diesem Foto der \u201EPerfection Loop\u201C-Knoten genutzt (auf YouTube gibt es Videos dazu) und anschlie\xDFend die restliche Schnur abgeschnitten.</p><p><img src="'+o+'" alt="Foto der angebundene Schnur mit Schleife"></p><p>Abschlie\xDFend k\xF6nnen wir die Antenne mit einem Antennenanalyzer (z. B. dem NanoVNA) f\xFCr das 2m und 70cm Band \xFCberpr\xFCfen. Danach bringen wir den Klettkabelbinder an einer Seite an, rollen das Kabel zusammen und die Antenne ist einsatzbereit. Die Antenne sollte dann so aussehen wie auf dem ersten Bild am Anfang dieser Anleitung.</p>',42),g=[p];function f(k,S){return n(),i("div",null,g)}var z=e(b,[["render",f],["__file","t2lt.html.vue"]]);export{z as default};
